/**
 * On success, responds with HTTP 302 redirect to `/my-reports?verified=1`.
 * @summary Consume magic-link token and set session cookie
 */
export const getVerifyMyReportsMagicLinkUrl = (
  params: VerifyMyReportsMagicLinkParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/my-reports/verify?${stringifiedParams}`
    : `/api/my-reports/verify`;
};

